const text = `${$json.subject || ''} ${$json.message || ''}`.toLowerCase();

const hasHardHighSignals =
  /(outage|system down|data loss|security breach|all customers|payment down|cannot login|service unavailable)/.test(text);

const hasMediumSignals =
  /(minor|formatting|single report|not urgent|next few days|non-critical|no outage|optional column)/.test(text);

// If classifier said high but ticket text clearly indicates medium and no hard-high signal, downgrade.
let urgency = String($json.urgency || '').toLowerCase();
if (urgency === 'high' && hasMediumSignals && !hasHardHighSignals) {
  urgency = 'medium';
}

return [{
  json: {
    ...$json,
    urgency
  }
}];
